+/**
+ * Safely stringify JSON for use in <script> tags.
+ * Escapes < characters to prevent XSS via </script> injection.
+ */
+export function safeJsonStringify(value: unknown): string {
+  return JSON.stringify(value).replace(/</g, "\\u003c");
